const express = require('express');
const http = require('http');
const app = express();
const server = http.createServer(app);
const plugins = process.env.PLUGINS ? process.env.PLUGINS.split(',') : [];

// Middleware to modify requests
app.use((req, res, next) => {
    plugins.forEach((plugin) => {
        try {
            const pluginModule = require(`./plugins/${plugin}`);
            pluginModule.requestHandler(req, res);
        } catch (error) {
            console.log(`Error loading plugin ${plugin}: ${error.message}`);
        }
    });
    next();
});

// Middleware to modify responses
app.use((req, res, next) => {
    plugins.forEach((plugin) => {
        try {
            const pluginModule = require(`./plugins/${plugin}`);
            pluginModule.responseHandler(req, res);
        } catch (error) {
            console.log(`Error loading plugin ${plugin}: ${error.message}`);
        }
    });
    next();
});

app.get('/', (req, res) => {
    res.send('API Gateway');
});

server.listen(3000, () => {
    console.log('API gateway listening on port 3000');
});

process.on('uncaughtException', (err) => {
    console.log(`Caught exception: ${err}\n`);
});